mapper.select:
select

,k.kecheng_name as kechengName
,j.jiaoshi_name as jiaoshiName
from course_chapter a
left join kecheng k on a.kecheng_id = k.id
left join jiaoshi j on k.jiaoshi_id = j.id


        and a.kecheng_id = #{params.kechengId}


        and a.chapter_name like concat('%',#{params.chapterName},'%')


        and a.chapter_status = #{params.chapterStatus}


        and k.jiaoshi_id = #{params.jiaoshiId}


        and a.is_deleted = #{params.isDeleted}


order by a.chapter_sort asc,a.${params.sort} ${params.order}
